import React, { useEffect, useRef, useState } from 'react';
import { useLocation, useNavigate, useSearchParams } from 'react-router-dom';
import { motion } from 'framer-motion';
import { calculateFaceType } from '../utils/calculateType';
import { faceTypes } from '../data/questions';
import { Share2, RefreshCw, Check, Star, AlertTriangle, Sparkles, User, Camera, Palette, Scissors } from 'lucide-react';
import xiaohongshuQr from '../assets/xiaohongshu-qr.jpg';
import { createEdgeSpark } from "@edgespark/client";

const Result: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isCopied, setIsCopied] = useState(false);
  
  // Get answers from URL or state
  const answersStr = searchParams.get('answers');
  const answers = answersStr ? JSON.parse(answersStr) : location.state?.answers;
  
  useEffect(() => {
    if (!answers) {
      navigate('/');
    }
  }, [answers, navigate]);

  if (!answers) return null;

  const resultKey = calculateFaceType(answers);
  const result = faceTypes[resultKey];

  useEffect(() => {
    const submitResult = async () => {
      let code = localStorage.getItem('invitationCode');
      if (!code) {
        code = 'user_' + Math.random().toString(36).substring(2, 8);
        localStorage.setItem('invitationCode', code);
      }
      
      if (resultKey) {
        try {
          const client = createEdgeSpark({ baseUrl: "https://staging--60jftjyxum0ii2uoko9d.youbase.cloud" });
          await client.api.fetch('/api/public/submit-result', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              code,
              faceType: resultKey,
              answers
            })
          });
        } catch (e) {
          console.error('Failed to submit result', e);
        }
      }
    };
    submitResult();
  }, [resultKey, answers]);

  const handleShare = async () => {
    const shareData = {
      title: '颜分析 - Face Type Diagnosis',
      text: `我是${result.name}！快来测测你的脸型吧。`,
      url: window.location.href,
    };

    const copyToClipboard = async () => {
      try {
        await navigator.clipboard.writeText(`${shareData.text} ${shareData.url}`);
        setIsCopied(true);
        setTimeout(() => setIsCopied(false), 2000);
      } catch (err) {
        console.log('Error copying:', err);
        alert('复制链接失败，请手动复制浏览器地址栏链接');
      }
    };

    // Check if we are in WeChat browser
    const isWeChat = /MicroMessenger/i.test(navigator.userAgent);

    if (isWeChat) {
      // In WeChat, navigator.share is often restricted or behaves unexpectedly.
      // Best practice is to prompt the user to use the native top-right menu.
      alert('请点击右上角【...】选择【发送给朋友】或【分享到朋友圈】');
      return;
    }

    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        console.log('Error sharing:', err);
        // Fallback to clipboard if share fails (e.g. user cancelled or not supported)
        await copyToClipboard();
      }
    } else {
      await copyToClipboard();
    }
  };

  // Draw Matrix
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;
    const centerX = width / 2;
    const centerY = height / 2;
    const scale = width / 25; // Scale factor

    // Clear
    ctx.clearRect(0, 0, width, height);

    // Draw Background Zones
    ctx.fillStyle = '#fff0f5'; // Top-Left (Adult/Curve - Feminine)
    ctx.fillRect(0, 0, centerX, centerY);
    ctx.fillStyle = '#f0f8ff'; // Top-Right (Adult/Straight - Cool)
    ctx.fillRect(centerX, 0, centerX, centerY);
    ctx.fillStyle = '#fffacd'; // Bottom-Left (Child/Curve - Cute)
    ctx.fillRect(0, centerY, centerX, centerY);
    ctx.fillStyle = '#f0fff0'; // Bottom-Right (Child/Straight - Cool Casual)
    ctx.fillRect(centerX, centerY, centerX, centerY);

    // Draw Axes
    ctx.beginPath();
    ctx.strokeStyle = '#cbd5e1';
    ctx.lineWidth = 1;
    ctx.moveTo(0, centerY);
    ctx.lineTo(width, centerY);
    ctx.moveTo(centerX, 0);
    ctx.lineTo(centerX, height);
    ctx.stroke();

    // Draw Labels for 8 Types
    const types = [
      { name: '可爱型', x: -8, y: -8, color: '#ec4899' },
      { name: '活泼可爱', x: -6, y: -6, color: '#f43f5e' },
      { name: '清新自然', x: 0, y: -5, color: '#10b981' },
      { name: '酷帅休闲', x: 8, y: -8, color: '#0ea5e9' },
      { name: '温柔女性', x: -8, y: 8, color: '#d946ef' },
      { name: '柔和优雅', x: 0, y: 5, color: '#8b5cf6' },
      { name: '华丽优雅', x: 2, y: 8, color: '#a855f7' },
      { name: '酷帅型', x: 10, y: 10, color: '#3b82f6' },
    ];

    ctx.font = 'bold 10px sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    types.forEach(t => {
      const tx = centerX + (t.x * scale);
      const ty = centerY - (t.y * scale);
      ctx.beginPath();
      ctx.arc(tx, ty, 3, 0, Math.PI * 2);
      ctx.fillStyle = t.color;
      ctx.fill();
      ctx.fillStyle = '#475569';
      ctx.fillText(t.name, tx, ty + 12);
    });

    // Axis Labels
    ctx.font = '12px sans-serif';
    ctx.fillStyle = '#64748b';
    ctx.textAlign = 'center';
    ctx.fillText('孩子脸 (Child)', centerX, height - 10);
    ctx.fillText('大人脸 (Adult)', centerX, 15);
    ctx.textAlign = 'left';
    ctx.fillText('直线', width - 30, centerY - 10);
    ctx.textAlign = 'right';
    ctx.fillText('曲线', 30, centerY - 10);

    // Plot User Point
    const userX = centerX + (result.matrixPosition.x * scale);
    const userY = centerY - (result.matrixPosition.y * scale);

    ctx.beginPath();
    ctx.arc(userX, userY, 15, 0, Math.PI * 2);
    ctx.strokeStyle = 'rgba(236, 72, 153, 0.5)';
    ctx.lineWidth = 4;
    ctx.stroke();

    ctx.beginPath();
    ctx.arc(userX, userY, 8, 0, Math.PI * 2);
    ctx.fillStyle = '#ec4899';
    ctx.fill();
    ctx.strokeStyle = '#fff';
    ctx.lineWidth = 3;
    ctx.stroke();

    ctx.fillStyle = '#ec4899';
    ctx.font = 'bold 12px sans-serif';
    ctx.fillText('YOU', userX, userY - 15);

  }, [result]);

  // Helper component for section headers
  const SectionHeader = ({ icon: Icon, title, color = "text-slate-800" }: { icon: any, title: string, color?: string }) => (
    <h3 className={`font-bold text-xl ${color} mb-6 flex items-center border-b border-slate-100 pb-3`}>
      <Icon className="w-6 h-6 mr-2" />
      {title}
    </h3>
  );

  return (
    <div className="min-h-screen bg-[#FDFBF7] py-12 px-4 md:px-8 font-sans">
      <div className="max-w-4xl mx-auto space-y-12">
        
        {/* Header */}
        <motion.div 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="text-center space-y-6"
        >
          <div className="inline-block px-4 py-1 bg-slate-900 text-white text-xs tracking-widest uppercase rounded-full">
            Face Analysis Report
          </div>
          <h1 className="text-4xl md:text-6xl font-serif font-bold text-slate-900">
            {result.name}
          </h1>
          <p className="text-xl text-slate-600 max-w-2xl mx-auto font-light leading-relaxed">
            {result.analysis.summary.text}
          </p>
          <div className="flex flex-wrap justify-center gap-2">
            {result.analysis.summary.keywords.map(k => (
              <span key={k} className="px-3 py-1 bg-pink-50 text-pink-600 text-sm rounded-full border border-pink-100">
                #{k}
              </span>
            ))}
          </div>
        </motion.div>

        {/* Top Section: Visuals & Basic Info */}
        <div className="grid grid-cols-1 md:grid-cols-12 gap-8">
          {/* Left: Images (5 cols) */}
          <motion.div 
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ delay: 0.2 }}
            className="md:col-span-5 space-y-6"
          >
            <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100">
              <img src={result.image} alt={result.name} className="w-full rounded-xl mb-4" />
              <div className="grid grid-cols-2 gap-3">
                <img src={result.realFaceImage} alt="Face Ref" className="w-full rounded-lg aspect-square object-cover" />
                <img src={result.realBodyImage} alt="Body Ref" className="w-full rounded-lg aspect-square object-cover" />
              </div>
            </div>
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col items-center">
              <h4 className="font-bold text-slate-700 mb-4 text-sm">脸型坐标矩阵</h4>
              <canvas ref={canvasRef} width={300} height={300} className="w-full max-w-[300px] h-auto" />
            </div>
          </motion.div>

          {/* Right: Analysis (7 cols) */}
          <motion.div 
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ delay: 0.3 }}
            className="md:col-span-7 space-y-8"
          >
            {/* 0. Features & Impression (Restored) */}
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100">
              <SectionHeader icon={Sparkles} title="特征与印象" />
              <div className="space-y-6">
                <div>
                  <p className="text-xs text-slate-400 mb-2 font-bold uppercase tracking-wider">面部特征</p>
                  <div className="flex flex-wrap gap-2">
                    {result.features.map(f => (
                      <span key={f} className="px-3 py-1 bg-slate-100 text-slate-600 rounded-full text-sm">
                        {f}
                      </span>
                    ))}
                  </div>
                </div>
                <div>
                  <p className="text-xs text-slate-400 mb-2 font-bold uppercase tracking-wider">给人的印象</p>
                  <div className="flex flex-wrap gap-2">
                    {result.impression.map(i => (
                      <span key={i} className="px-3 py-1 bg-pink-50 text-pink-600 rounded-full text-sm">
                        {i}
                      </span>
                    ))}
                  </div>
                </div>
              </div>
            </div>

            {/* 1. Face Type Judgment */}
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100">
              <SectionHeader icon={User} title="一、脸型判定" />
              <div className="space-y-4">
                <div className="flex items-baseline">
                  <span className="text-slate-500 w-24 flex-shrink-0">主脸型</span>
                  <span className="text-lg font-bold text-slate-900">{result.analysis.faceType.main}</span>
                </div>
                {result.analysis.faceType.secondary && (
                  <div className="flex items-baseline">
                    <span className="text-slate-500 w-24 flex-shrink-0">次脸型</span>
                    <span className="text-slate-700">{result.analysis.faceType.secondary}</span>
                  </div>
                )}
                <div className="bg-slate-50 p-4 rounded-lg text-slate-600 text-sm leading-relaxed">
                  {result.analysis.faceType.reason}
                </div>
              </div>
            </div>

            {/* 2. Structure & Ratio */}
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100">
              <SectionHeader icon={Camera} title="二、比例与结构" />
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                <div>
                  <h5 className="font-bold text-slate-700 mb-2 text-sm">三庭比例</h5>
                  <p className="text-slate-600 text-sm">{result.analysis.structure.ratio}</p>
                </div>
                <div>
                  <h5 className="font-bold text-slate-700 mb-2 text-sm">五眼分布</h5>
                  <p className="text-slate-600 text-sm">{result.analysis.structure.eyes}</p>
                </div>
                <div>
                  <h5 className="font-bold text-slate-700 mb-2 text-sm">面部纵深</h5>
                  <p className="text-slate-600 text-sm">{result.analysis.structure.depth}</p>
                </div>
                <div>
                  <h5 className="font-bold text-slate-700 mb-2 text-sm">骨相皮相</h5>
                  <p className="text-slate-600 text-sm">{result.analysis.structure.bone}</p>
                </div>
              </div>
            </div>

            {/* 3. Lines & Vibe */}
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100">
              <SectionHeader icon={Sparkles} title="三、线条与气质" />
              <div className="space-y-4">
                <div className="flex items-start">
                  <span className="text-slate-500 w-24 flex-shrink-0 pt-1">线条属性</span>
                  <p className="text-slate-700">{result.analysis.lines.attribute}</p>
                </div>
                <div className="flex items-start">
                  <span className="text-slate-500 w-24 flex-shrink-0 pt-1">气质倾向</span>
                  <p className="text-slate-700">{result.analysis.lines.vibe}</p>
                </div>
                <div className="flex items-start">
                  <span className="text-slate-500 w-24 flex-shrink-0 pt-1">视觉重心</span>
                  <p className="text-slate-700">{result.analysis.lines.focus}</p>
                </div>
              </div>
            </div>
          </motion.div>
        </div>

        {/* Full Width Sections */}
        <motion.div 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.4 }}
          className="space-y-8"
        >
          {/* Basic Style Guide (Restored) */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {/* Fashion */}
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100">
              <SectionHeader icon={Palette} title="基础穿搭指南" color="text-blue-600" />
              <div className="space-y-4 text-slate-600 text-sm leading-relaxed">
                <p><strong className="text-slate-900">风格：</strong>{result.fashion.style}</p>
                <p><strong className="text-slate-900">上装：</strong>{result.fashion.tops}</p>
                <p><strong className="text-slate-900">下装：</strong>{result.fashion.bottoms}</p>
                <p><strong className="text-slate-900">图案：</strong>{result.fashion.patterns}</p>
                <p><strong className="text-slate-900">配饰：</strong>{result.fashion.accessories}</p>
                <p><strong className="text-slate-900">鞋包：</strong>{result.fashion.shoes} / {result.fashion.bag}</p>
              </div>
            </div>

            {/* Hair & Makeup */}
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100">
              <SectionHeader icon={Scissors} title="基础妆发指南" color="text-purple-600" />
              <div className="space-y-4 text-slate-600 text-sm leading-relaxed">
                <p><strong className="text-slate-900">发长：</strong>{result.hair.length}</p>
                <p><strong className="text-slate-900">造型：</strong>{result.hair.style}</p>
                <p><strong className="text-slate-900">刘海：</strong>{result.hair.bangs}</p>
                <div className="h-px bg-slate-100 my-2"></div>
                <p><strong className="text-slate-900">妆容重点：</strong>{result.makeup}</p>
              </div>
            </div>
          </div>

          {/* 4. Suggestions */}
          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100">
            <SectionHeader icon={Check} title="四、优势强化建议" color="text-green-600" />
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-2">
                <h5 className="font-bold text-slate-800">发型建议</h5>
                <p className="text-slate-600 text-sm leading-relaxed">{result.analysis.suggestions.hair}</p>
              </div>
              <div className="space-y-2">
                <h5 className="font-bold text-slate-800">妆容风格</h5>
                <p className="text-slate-600 text-sm leading-relaxed">{result.analysis.suggestions.makeup}</p>
              </div>
              <div className="space-y-2">
                <h5 className="font-bold text-slate-800">穿搭方向</h5>
                <p className="text-slate-600 text-sm leading-relaxed">{result.analysis.suggestions.outfit}</p>
              </div>
              <div className="space-y-2">
                <h5 className="font-bold text-slate-800">配饰点缀</h5>
                <p className="text-slate-600 text-sm leading-relaxed">{result.analysis.suggestions.accessories}</p>
              </div>
            </div>
          </div>

          {/* 5. Avoid */}
          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100">
            <SectionHeader icon={AlertTriangle} title="五、避雷建议" color="text-red-500" />
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="bg-red-50 p-4 rounded-xl">
                <h5 className="font-bold text-red-700 mb-2 text-sm">发型避雷</h5>
                <p className="text-red-600 text-sm">{result.analysis.avoid.hair}</p>
              </div>
              <div className="bg-red-50 p-4 rounded-xl">
                <h5 className="font-bold text-red-700 mb-2 text-sm">妆容避雷</h5>
                <p className="text-red-600 text-sm">{result.analysis.avoid.makeup}</p>
              </div>
              <div className="bg-red-50 p-4 rounded-xl">
                <h5 className="font-bold text-red-700 mb-2 text-sm">修容避雷</h5>
                <p className="text-red-600 text-sm">{result.analysis.avoid.contour}</p>
              </div>
            </div>
          </div>

          {/* 6 & 8. Celebrity & Commercial */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="bg-slate-900 text-white p-8 rounded-2xl shadow-sm">
              <SectionHeader icon={Star} title="六、名人对标" color="text-white" />
              <div className="space-y-6">
                <div>
                  <p className="text-slate-400 text-sm mb-2">相似名人</p>
                  <p className="text-2xl font-serif">{result.analysis.celebrityReference.names.join('、')}</p>
                </div>
                <div>
                  <p className="text-slate-400 text-sm mb-2">相似点</p>
                  <p className="text-slate-300 leading-relaxed">{result.analysis.celebrityReference.similarity}</p>
                </div>
              </div>
            </div>

            <div className="bg-gradient-to-br from-purple-50 to-pink-50 p-8 rounded-2xl shadow-sm border border-purple-100">
              <SectionHeader icon={Sparkles} title="八、进阶商业化" color="text-purple-800" />
              <div className="space-y-4 text-sm">
                <div className="flex">
                  <span className="font-bold text-purple-900 w-20 flex-shrink-0">IP方向</span>
                  <span className="text-purple-800">{result.analysis.commercial.ip}</span>
                </div>
                <div className="flex">
                  <span className="font-bold text-purple-900 w-20 flex-shrink-0">拍照构图</span>
                  <span className="text-purple-800">{result.analysis.commercial.photo}</span>
                </div>
                <div className="flex">
                  <span className="font-bold text-purple-900 w-20 flex-shrink-0">头像建议</span>
                  <span className="text-purple-800">{result.analysis.commercial.avatar}</span>
                </div>
                <div className="flex">
                  <span className="font-bold text-purple-900 w-20 flex-shrink-0">风格进阶</span>
                  <span className="text-purple-800">{result.analysis.commercial.upgrade}</span>
                </div>
              </div>
            </div>
          </div>
        </motion.div>

        {/* Xiaohongshu Section */}
        <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100 text-center space-y-6">
          <h3 className="text-xl font-bold text-slate-900">了解更多定制穿搭美学</h3>
          <p className="text-slate-600">请联系小红书号：<span className="font-mono font-bold text-slate-800">95116119883</span></p>
          <div className="flex justify-center">
            <img src={xiaohongshuQr} alt="Xiaohongshu QR" className="w-48 h-48 object-contain rounded-lg border border-slate-200" />
          </div>
          <p className="text-sm text-slate-400">扫码或搜索添加，获取一对一咨询</p>
        </div>

        {/* Actions */}
        <div className="flex flex-col sm:flex-row gap-4 justify-center pt-8 pb-12">
          <button
            onClick={() => navigate('/')}
            className="flex items-center justify-center px-8 py-4 bg-white text-slate-900 rounded-full font-bold shadow-sm border border-slate-200 hover:bg-slate-50 transition-colors"
          >
            <RefreshCw className="w-5 h-5 mr-2" />
            重新测试
          </button>
          <button
            onClick={handleShare}
            className="flex items-center justify-center px-8 py-4 bg-slate-900 text-white rounded-full font-bold shadow-lg hover:bg-slate-800 transition-colors"
          >
            {isCopied ? <Check className="w-5 h-5 mr-2" /> : <Share2 className="w-5 h-5 mr-2" />}
            {isCopied ? '已复制链接' : '分享结果'}
          </button>
        </div>

      </div>
    </div>
  );
};

export default Result;
