import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowLeft, CheckCircle2 } from 'lucide-react';
import { questions, AnswerValue } from '../data/questions';

const Test: React.FC = () => {
  const navigate = useNavigate();
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState<Record<number, AnswerValue>>({});
  const [direction, setDirection] = useState(1);

  const currentQuestion = questions[currentQuestionIndex];
  const progress = ((currentQuestionIndex + 1) / questions.length) * 100;

  const handleAnswer = (value: AnswerValue) => {
    const newAnswers = { ...answers, [currentQuestion.id]: value };
    setAnswers(newAnswers);

    if (currentQuestionIndex < questions.length - 1) {
      setDirection(1);
      setTimeout(() => setCurrentQuestionIndex(prev => prev + 1), 200);
    } else {
      // Finish test - Navigate with URL params for persistence
      const params = new URLSearchParams();
      params.set('answers', JSON.stringify(newAnswers));
      navigate(`/result?${params.toString()}`);
    }
  };

  const handleBack = () => {
    if (currentQuestionIndex > 0) {
      setDirection(-1);
      setCurrentQuestionIndex(prev => prev - 1);
    } else {
      navigate('/');
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 md:p-8">
      {/* Progress Bar */}
      <div className="fixed top-0 left-0 w-full h-2 bg-slate-200">
        <motion.div 
          className="h-full bg-pink-500"
          initial={{ width: 0 }}
          animate={{ width: `${progress}%` }}
          transition={{ duration: 0.3 }}
        />
      </div>

      <div className="w-full max-w-2xl">
        <button 
          onClick={handleBack}
          className="mb-8 flex items-center text-slate-500 hover:text-slate-800 transition-colors"
        >
          <ArrowLeft className="w-5 h-5 mr-2" />
          返回
        </button>

        <AnimatePresence mode="wait" custom={direction}>
          <motion.div
            key={currentQuestion.id}
            custom={direction}
            initial={{ opacity: 0, x: direction * 50 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: direction * -50 }}
            transition={{ duration: 0.3 }}
            className="bg-white rounded-2xl shadow-xl p-8 md:p-12"
          >
            <div className="mb-8">
              <span className="inline-block px-3 py-1 bg-slate-100 text-slate-600 rounded-full text-sm font-medium mb-4">
                Question {currentQuestionIndex + 1} / {questions.length}
              </span>
              <h2 className="text-2xl md:text-3xl font-bold text-slate-900 mb-2">
                {currentQuestion.text}
              </h2>
              <p className="text-slate-500">
                {currentQuestion.category === 'generation' ? '世代感分析' : '形状分析'}
              </p>
            </div>

            <div className="space-y-4">
              {currentQuestion.options.map((option) => (
                <button
                  key={option.value}
                  onClick={() => handleAnswer(option.value)}
                  className={`w-full text-left p-6 rounded-xl border-2 transition-all duration-200 group relative overflow-hidden
                    ${answers[currentQuestion.id] === option.value 
                      ? 'border-pink-500 bg-pink-50' 
                      : 'border-slate-100 hover:border-pink-200 hover:bg-slate-50'
                    }`}
                >
                  <div className="relative z-10 flex items-center justify-between">
                    <div>
                      <span className={`text-lg font-bold block mb-1 ${
                        answers[currentQuestion.id] === option.value ? 'text-pink-600' : 'text-slate-800'
                      }`}>
                        {option.label}
                      </span>
                      {option.description && (
                        <span className="text-sm text-slate-500">
                          {option.description}
                        </span>
                      )}
                    </div>
                    {answers[currentQuestion.id] === option.value && (
                      <CheckCircle2 className="w-6 h-6 text-pink-500" />
                    )}
                  </div>
                </button>
              ))}
            </div>

            {currentQuestion.hint && (
              <div className="mt-6 p-4 bg-blue-50 text-blue-700 rounded-xl text-sm leading-relaxed flex items-start">
                <span className="mr-2">💡</span>
                <span>{currentQuestion.hint}</span>
              </div>
            )}
          </motion.div>
        </AnimatePresence>
      </div>
    </div>
  );
};

export default Test;
