import React, { useEffect, useState } from 'react';
import { createEdgeSpark } from "@edgespark/client";
import { faceTypes } from '../data/questions';

const client = createEdgeSpark({ baseUrl: "https://staging--60jftjyxum0ii2uoko9d.youbase.cloud" });

interface Report {
  id: number;
  code: string;
  faceType: string;
  answers: string;
  createdAt: number;
}

const AdminReports: React.FC = () => {
  const [reports, setReports] = useState<Report[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchReports = async () => {
      try {
        const res = await client.api.fetch('/api/public/reports');
        const data = await res.json();
        setReports(data.results);
      } catch (e) {
        console.error(e);
      } finally {
        setLoading(false);
      }
    };
    fetchReports();
  }, []);

  if (loading) return <div className="p-8 text-center">Loading...</div>;

  return (
    <div className="min-h-screen bg-slate-50 p-8">
      <div className="max-w-6xl mx-auto">
        <h1 className="text-2xl font-bold mb-6">用户测试报告 (Admin)</h1>
        <div className="bg-white rounded-xl shadow overflow-hidden">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-100 text-slate-600 uppercase font-bold">
              <tr>
                <th className="p-4">ID</th>
                <th className="p-4">邀请码</th>
                <th className="p-4">脸型结果</th>
                <th className="p-4">测试时间</th>
                <th className="p-4">操作</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {reports.map(r => (
                <tr key={r.id} className="hover:bg-slate-50">
                  <td className="p-4 text-slate-500">#{r.id}</td>
                  <td className="p-4 font-mono font-medium">{r.code}</td>
                  <td className="p-4">
                    <span className="px-2 py-1 bg-pink-100 text-pink-700 rounded text-xs font-bold">
                      {faceTypes[r.faceType as keyof typeof faceTypes]?.name || r.faceType}
                    </span>
                  </td>
                  <td className="p-4 text-slate-500">
                    {new Date(r.createdAt).toLocaleString()}
                  </td>
                  <td className="p-4">
                    <a 
                      href={`/result?answers=${encodeURIComponent(r.answers)}`}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="text-blue-600 hover:text-blue-800 text-xs font-bold border border-blue-200 px-3 py-1 rounded-full hover:bg-blue-50 transition-colors"
                    >
                      查看报告
                    </a>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default AdminReports;
