import { AnswerValue, FaceTypeKey, questions } from '../data/questions';

export const calculateFaceType = (answers: Record<number, AnswerValue>): FaceTypeKey => {
  let childScore = 0;
  let adultScore = 0;
  let curveScore = 0;
  let straightScore = 0;
  let largeEyes = false;

  // Calculate scores
  Object.entries(answers).forEach(([questionIdStr, value]) => {
    const questionId = parseInt(questionIdStr);
    const question = questions.find((q) => q.id === questionId);

    if (!question) return;

    if (question.category === 'generation') {
      if (value === 'A') childScore++;
      if (value === 'B') adultScore++;
      
      // Check for large eyes (Question 6)
      if (questionId === 6 && value === 'B') {
        largeEyes = true;
      }
    } else if (question.category === 'shape') {
      if (value === 'C') curveScore++;
      if (value === 'D') straightScore++;
    }
  });

  const isAdult = adultScore >= childScore;
  
  // Shape classification
  // High Curve: Curve > Straight + 2
  // High Straight: Straight > Curve + 2
  // Mix: Difference <= 2
  const diff = Math.abs(curveScore - straightScore);
  const isMix = diff <= 2;
  const isCurve = curveScore > straightScore && !isMix;
  const isStraight = straightScore > curveScore && !isMix;

  if (!isAdult) {
    // Child Types
    if (isCurve) {
      return largeEyes ? 'active_cute' : 'cute';
    }
    if (isStraight) {
      return 'cool_casual';
    }
    // Mix
    return 'fresh';
  } else {
    // Adult Types
    if (isCurve) {
      return 'feminine';
    }
    if (isStraight) {
      return 'cool';
    }
    // Mix
    return largeEyes ? 'elegant' : 'soft_elegant';
  }
};
